class Solution {
public:
    vector<int> evenOddBit(int n) {
        int even = 0, odd = 0;
        int index = 0;
        while (n) {
            if (n & 1) {
                if (index % 2 == 0) even++;
                else odd++;
            }
            n >>= 1;
            index++;
        }
        return {even, odd};
    }
};
